@Test
    void sendReturnsZeroIfItCantFitAnEntireBatch()
    {
        messageTransceiver.send(InMemoryMessageTransceiver.SIZE, 8, 777, 100);

        final int result = messageTransceiver.send(1, 100, 555, 21);

        assertEquals(0, result);
    }

